142 public actor UsageHistoryReader {
143     public nonisolated let rootPath: String
144     private let fileManager: FileManager
145     private let logger: FileLogger
146 
147     public init(
148         rootPath: String? = nil,
149         fileManager: FileManager = .default,
150         logger: FileLogger = Loggers.app
151     ) {
152         let home = FileManager.default.homeDirectoryForCurrentUser.path
153         self.rootPath = rootPath ?? "\(home)/.cache/ai-usages-tracker/usage-history"
154         self.fileManager = fileManager
155         self.logger = logger
156     }
157 
158     public func load(window: UsageHistoryTimeWindow, now: Date = Date()) async -> UsageHistorySnapshot {
159         let startDate = window.startDate(relativeTo: now)
160         var points: [UsageHistoryPoint] = []
161         var skippedLineCount = 0
162         var hasDataBeforeWindow = false
163         var hasDataAfterWindow = false
164 
165         for url in jsonlFileURLs() {
166             let data: Data
167             do {
168                 data = try Data(contentsOf: url)
169             } catch {
170                 logger.log(.warning, "UsageHistoryReader: cannot read \(url.path): \(error)")
171                 continue
172             }
173 
174             let lines = data.split(separator: Self.newlineByte, omittingEmptySubsequences: true)
175             for line in lines {
176                 do {
177                     let tick = try JSONDecoder().decode(TickSnapshot.self, from: Data(line))
178                     guard let timestamp = tick.timestamp.date else {
179                         continue
180                     }
181                     if let startDate, timestamp < startDate {
182                         hasDataBeforeWindow = true
183                         continue
184                     }
185                     if timestamp > now {
186                         hasDataAfterWindow = true
187                         continue
188                     }
189                     points.append(contentsOf: Self.points(from: tick, timestamp: timestamp))
190                 } catch {
191                     skippedLineCount += 1
192                 }
193             }
194         }
195 
196         points.sort {
197             if $0.timestamp == $1.timestamp {
198                 return $0.seriesLabel.localizedStandardCompare($1.seriesLabel) == .orderedAscending
199             }
200             return $0.timestamp < $1.timestamp
201         }
202         return UsageHistorySnapshot(
203             points: points,
204             skippedLineCount: skippedLineCount,
205             hasDataBeforeWindow: window == .all ? false : hasDataBeforeWindow,
206             hasDataAfterWindow: window == .all ? false : hasDataAfterWindow
207         )
208     }
209 
210     private func jsonlFileURLs() -> [URL] {
211         let rootURL = URL(fileURLWithPath: rootPath, isDirectory: true)
212         guard let enumerator = fileManager.enumerator(
213             at: rootURL,
214             includingPropertiesForKeys: [.isRegularFileKey],
215             options: [.skipsHiddenFiles]
216         ) else {
217             return []
218         }
219 
220         var urls: [URL] = []
221         for case let url as URL in enumerator where url.pathExtension == "jsonl" {
222             let values = try? url.resourceValues(forKeys: [.isRegularFileKey])
223             if values?.isRegularFile != false {
224                 urls.append(url)
225             }
226         }
227         return urls.sorted { $0.path.localizedStandardCompare($1.path) == .orderedAscending }
228     }
229 
230     private static func points(from tick: TickSnapshot, timestamp: Date) -> [UsageHistoryPoint] {
231         tick.accounts.flatMap { account in
232             account.metrics.compactMap { metric in
233                 point(from: metric, account: account, timestamp: timestamp)
234             }
235         }
236     }
237 
238     private static func point(
239         from metric: MetricSnapshot,
240         account: AccountSnapshot,
241         timestamp: Date
242     ) -> UsageHistoryPoint? {
243         switch metric.kind {
244         case .timeWindow:
245             guard let usagePercent = metric.usagePercent else { return nil }
246             return UsageHistoryPoint(
247                 timestamp: timestamp,
248                 vendor: account.vendor,
249                 account: account.account,
250                 metricName: metric.name,
251                 metricKind: metric.kind,
252                 value: Double(usagePercent.rawValue),
253                 unit: "%"
254             )
255         case .payAsYouGo:
256             guard let currentAmount = metric.currentAmount else { return nil }
257             return UsageHistoryPoint(
258                 timestamp: timestamp,
259                 vendor: account.vendor,
260                 account: account.account,
261                 metricName: metric.name,
262                 metricKind: metric.kind,
263                 value: currentAmount,
264                 unit: metric.currency ?? ""
265             )
266         case .unknown:
267             return nil
268         }
269     }
270 
271     private static let newlineByte: UInt8 = 0x0A
272 }
273 
274 private extension MetricKind {
275     var rawValueForDisplay: String {
276         switch self {
277         case .timeWindow: "time-window"
278         case .payAsYouGo: "pay-as-you-go"
279         case .unknown(let rawValue): rawValue
280         }
281     }
282 }

