  5 struct UsageHistoryChartView: View {
  6     let snapshot: UsageHistorySnapshot
  7     let referenceDate: Date
  8     @Binding var selectedWindow: UsageHistoryTimeWindow
  9     let isLoading: Bool
 10     let onPreviousWindow: () -> Void
 11     let onNextWindow: () -> Void
 12 
 13     @State private var hiddenVendorIDs: Set<String> = []
 14     @State private var hiddenAccountIDs: Set<String> = []
 15     @State private var showWeeklyMetrics = true
 16     @State private var showNonWeeklyMetrics = true
 17 
 18     private var points: [UsageHistoryPoint] { snapshot.points }
 19     private var visiblePoints: [UsageHistoryPoint] {
 20         points.filter { point in
 21             !hiddenVendorIDs.contains(point.vendor.rawValue)
 22                 && !hiddenAccountIDs.contains(point.account.rawValue)
 23                 && (showWeeklyMetrics || !isWeekly(point.metricName))
 24                 && (showNonWeeklyMetrics || isWeekly(point.metricName))
 25         }
 26     }
 27 
 28     private var summaries: [UsageHistorySeriesSummary] {
 29         let grouped = Dictionary(grouping: visiblePoints, by: \.seriesID)
 30         return grouped.compactMap { seriesID, points in
 31             guard let latest = points.max(by: { $0.timestamp < $1.timestamp }) else { return nil }
 32             return UsageHistorySeriesSummary(
 33                 id: seriesID,
 34                 label: latest.seriesLabel,
 35                 latestValue: latest.value,
 36                 unit: latest.unit,
 37                 pointCount: points.count
 38             )
 39         }
 40         .sorted { $0.label.localizedStandardCompare($1.label) == .orderedAscending }
 41     }
 42 
 43     private var availableVendors: [String] {
 44         Array(Set(points.map(\.vendor.rawValue))).sorted {
 45             $0.localizedStandardCompare($1) == .orderedAscending
 46         }
 47     }
 48 
 49     private var availableAccounts: [String] {
 50         Array(Set(points.map(\.account.rawValue))).sorted {
 51             $0.localizedStandardCompare($1) == .orderedAscending
 52         }
 53     }
 54 
 55     private var seriesColors: [String: Color] {
 56         Dictionary(uniqueKeysWithValues: summaries.enumerated().map { index, summary in
 57             (summary.id, Self.palette[index % Self.palette.count])
 58         })
 59     }
 60 
 61     private var yAxisLabel: String {
 62         let units = Set(visiblePoints.map(\.unit).filter { !$0.isEmpty })
 63         if units.count == 1, let unit = units.first {
 64             return unit == "%" ? "Usage (%)" : "Usage (\(unit))"
 65         }
 66         return "Usage"
 67     }
 68 
 69     private var xDomain: ClosedRange<Date> {
 70         if let startDate = selectedWindow.startDate(relativeTo: referenceDate) {
 71             return startDate...referenceDate
 72         }
 73 
 74         guard let first = visiblePoints.first?.timestamp,
 75               let last = visiblePoints.last?.timestamp else {
 76             return referenceDate.addingTimeInterval(-60 * 60)...referenceDate
 77         }
 78         if first == last {
 79             return first.addingTimeInterval(-30 * 60)...last.addingTimeInterval(30 * 60)
 80         }
 81         return first...last
 82     }
 83 
 84     private var canNavigatePrevious: Bool {
 85         selectedWindow != .all && snapshot.hasDataBeforeWindow
 86     }
 87 
