 93         VStack(alignment: .leading, spacing: 10) {
 94             controls
 95 
 96             if isLoading, points.isEmpty {
 97                 loadingState
 98             } else if points.isEmpty {
 99                 emptyState
100             } else if visiblePoints.isEmpty {
101                 filteredEmptyState
102             } else {
103                 chart
104                 summaryRows
