131                 }
132             }
133             .pickerStyle(.segmented)
134             .labelsHidden()
135             .controlSize(.small)
136 
137             Button {
138                 onNextWindow()
139             } label: {
140                 Image(systemName: "chevron.right")
141                     .frame(width: 16, height: 16)
142                     .hoverAffordance(isEnabled: canNavigateNext)
143             }
144             .buttonStyle(.borderless)
145             .controlSize(.small)
146             .disabled(!canNavigateNext)
147             .help("Next time window")
148             .focusable(false)
149 
150             Menu {
