185     private var chart: some View {
186         Chart(visiblePoints) { point in
187             LineMark(
188                 x: .value("Time", point.timestamp),
189                 y: .value(yAxisLabel, point.value),
190                 series: .value("Metric", point.seriesLabel)
191             )
192             .interpolationMethod(.catmullRom)
193             .foregroundStyle(seriesColor(for: point.seriesID))
194         }
195         .chartLegend(.hidden)
196         .chartYAxisLabel(yAxisLabel)
197         .chartXScale(domain: xDomain)
198         .frame(height: 180)
199         .padding(8)
200         .background(Color(NSColor.controlBackgroundColor), in: RoundedRectangle(cornerRadius: 8))
201         .overlay(
202             RoundedRectangle(cornerRadius: 8)
203                 .strokeBorder(Color.primary.opacity(0.16), lineWidth: 1)
204         )
